UPDATE manhaj_lessons SET blocks = blocks || '[{"type": "heading", "level": 3, "text": "تابع الكلام عن اليوم الآخر؛ الصراط والشفاعات والجنة والنار:", "page": 178, "id": "unit-17__lesson-03__b01", "role": "section"}, {"type": "paragraph", "md": "7- ومن الإيمان باليوم الآخر: الإيمانُ بالصِّراط، وهو جسرٌ منصوبٌ على متن جهنَّم، يَمرُّ عليه المسلمون للوصول إلى الجنَّة على قَدْر أعمالهم؛ فمنهم مَن يَمُرُّ كالبرق، ومنهم مَن يَمُرُّ كالرِّيح، ومنهم مَن يَزحف زحفًا، فعن رسول الله صلى الله عليه وسلم : (فيُضربُ الصِّراطُ بين ظهرانَي جهنَّم، فأكون أوَّلَ مَن يجوز من الرُّسل بأمَّته، ولا يتكلَّمُ يومئذ أحدٌ إلَّا الرُّسُل، وكلامُ الرُّسل يومئذ: اللَّهمَّ سلِّم سلِّم، وفي جهنَّم كلاليب مثل شَوك السَّعدان، هل رأيتُم شَوكَ السَّعدان؟ قالوا: نعم، قال: فإنَّها مثل شوك السَّعدان، غير أنَّه لا يَعلمُ قدر عِظَمها إلَّا الله، تَخطفُ الناسَ بأعمالِهم، فمنهم مَن يُوبَقُ بعمله، ومنهم مَن يُخردَل ثم ينجو).", "page": 178, "id": "unit-17__lesson-03__b02", "inline": [{"t": "emphasis", "s": "7- ومن الإيمان باليوم الآخر: الإيمانُ بالصِّراط", "role": "emphasis"}, {"t": "text", "s": "، وهو جسرٌ منصوبٌ على متن جهنَّم، يَمرُّ عليه المسلمون للوصول إلى الجنَّة على قَدْر أعمالهم؛ فمنهم مَن يَمُرُّ كالبرق، ومنهم مَن يَمُرُّ كالرِّيح، ومنهم مَن يَزحف زحفًا، فعن رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(فيُضربُ الصِّراطُ بين ظهرانَي جهنَّم، فأكون أوَّلَ مَن يجوز من الرُّسل بأمَّته، ولا يتكلَّمُ يومئذ أحدٌ إلَّا الرُّسُل، وكلامُ الرُّسل يومئذ: اللَّهمَّ سلِّم سلِّم، وفي جهنَّم كلاليب مثل شَوك السَّعدان، هل رأيتُم شَوكَ السَّعدان؟ قالوا: نعم، قال: فإنَّها مثل شوك السَّعدان، غير أنَّه لا يَعلمُ قدر عِظَمها إلَّا الله، تَخطفُ الناسَ بأعمالِهم، فمنهم مَن يُوبَقُ بعمله، ومنهم مَن يُخردَل ثم ينجو)", "role": "emphasis"}, {"t": "text", "s": "."}], "list": {"type": "ordered", "marker": "7"}}, {"type": "paragraph", "md": "8- ومن الإيمان باليوم الآخر: الإيمان بالشَّفاعات التي وردت في الكتاب والسنَّة، والتي منها: الشفاعة العظمى الخاصَّة بنبيِّنا صلى الله عليه وسلم في تخليص أهل الموقف مِمَّا هم فيه من البلاء في أرض الحشر، وهي المقام المحمود الذي يحمده عليه الأوَّلون والآخرون، من لَدن آدم عليه السلام إلى الذين قامت عليهم الساعة من الخلق.", "page": 178, "id": "unit-17__lesson-03__b03", "inline": [{"t": "text", "s": "8- "}, {"t": "emphasis", "s": "ومن الإيمان باليوم الآخر: الإيمان بالشَّفاعات", "role": "emphasis"}, {"t": "text", "s": " التي وردت في الكتاب والسنَّة، والتي "}, {"t": "emphasis", "s": "منها:", "role": "emphasis"}, {"t": "text", "s": " الشفاعة العظمى الخاصَّة بنبيِّنا "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في تخليص أهل الموقف مِمَّا هم فيه من البلاء في أرض الحشر، وهي المقام المحمود الذي يحمده عليه الأوَّلون والآخرون، من لَدن آدم "}, {"t": "honorific", "s": "عليه السلام"}, {"t": "text", "s": " إلى الذين قامت عليهم الساعة من الخلق."}], "list": {"type": "ordered", "marker": "8"}}, {"type": "paragraph", "md": "ومنها: الشفاعة فيمَن استحقَّ النارَ ألاَّ يدخلها، ويدلُّ لذلك قول النَّبيِّ صلى الله عليه وسلم وغيره من الأنبياء على الصراط: (اللَّهمَّ سلِّم سلِّم!). ومنها: الشفاعة في رفع درجات مَن يدخل الجنَّة فيها فوق ما كان يقتضيه ثواب أعمالهم، ويدلُّ لذلك قوله تعالى: ﴿وَٱلَّذِينَ ءَامَنُواْ وَٱتَّبَعَتۡهُمۡ ذُرِّيَّتُهُم بِإِيمَٰنٍ أَلۡحَقۡنَا بِهِمۡ ذُرِّيَّتَهُمۡ وَمَآ أَلَتۡنَٰهُم مِّنۡ عَمَلِهِم مِّن شَيۡءٖۚ كُلُّ ٱمۡرِيِٕۭ بِمَا كَسَبَ رَهِينٞ ۝٢١﴾، ومنه رفع درجات زوجاته صلى الله عليه وسلم إلى درجته.", "page": 178, "id": "unit-17__lesson-03__b04", "inline": [{"t": "emphasis", "s": "ومنها", "role": "emphasis"}, {"t": "text", "s": ": الشفاعة فيمَن استحقَّ النارَ ألاَّ يدخلها، ويدلُّ لذلك قول النَّبيِّ "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " وغيره من الأنبياء على الصراط: "}, {"t": "emphasis", "s": "(اللَّهمَّ سلِّم سلِّم!)", "role": "emphasis"}, {"t": "text", "s": ". "}, {"t": "emphasis", "s": "ومنها", "role": "emphasis"}, {"t": "text", "s": ": الشفاعة في رفع درجات مَن يدخل الجنَّة فيها فوق ما كان يقتضيه ثواب أعمالهم، ويدلُّ لذلك قوله تعالى: "}, {"t": "ayah", "s": "وَٱلَّذِينَ ءَامَنُواْ وَٱتَّبَعَتۡهُمۡ ذُرِّيَّتُهُم بِإِيمَٰنٍ أَلۡحَقۡنَا بِهِمۡ ذُرِّيَّتَهُمۡ وَمَآ أَلَتۡنَٰهُم مِّنۡ عَمَلِهِم مِّن شَيۡءٖۚ كُلُّ ٱمۡرِيِٕۭ بِمَا كَسَبَ رَهِينٞ ۝٢١", "ayah": [21], "verses": [{"n": 21, "text": "وَٱلَّذِينَ ءَامَنُواْ وَٱتَّبَعَتۡهُمۡ ذُرِّيَّتُهُم بِإِيمَٰنٍ أَلۡحَقۡنَا بِهِمۡ ذُرِّيَّتَهُمۡ وَمَآ أَلَتۡنَٰهُم مِّنۡ عَمَلِهِم مِّن شَيۡءٖۚ كُلُّ ٱمۡرِيِٕۭ بِمَا كَسَبَ رَهِينٞ", "surah": 52, "ref_api": "https://api.quran.com/api/v4/verses/by_key/52:21", "surah_name": "الطور", "ayah_canonical": 21, "match": "exact", "ref": "52:21"}], "surah": null, "ref_api": null}, {"t": "text", "s": "، ومنه رفع درجات زوجاته "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " إلى درجته."}]}, {"type": "paragraph", "md": "ومنها: شفاعته صلى الله عليه وسلم في دخول الجنَّة، ويدلُّ له قوله صلى الله عليه وسلم : (أنا أوَّل الناس يشفع في الجنة، وأنا أكثرُ الأنبياء تَبَعًا)", "page": 178, "id": "unit-17__lesson-03__b05", "inline": [{"t": "emphasis", "s": "ومنها", "role": "emphasis"}, {"t": "text", "s": ": شفاعته "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " في دخول الجنَّة، ويدلُّ له قوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(أنا أوَّل الناس يشفع في الجنة، وأنا أكثرُ الأنبياء تَبَعًا)", "role": "emphasis"}]}, {"type": "paragraph", "md": "ومنها: الشفاعة في إخراج أهل الكبائر من النار، وقد تواترت بذلك الأحاديث؛ قال رسول الله صلى الله عليه وسلم : (لكلِّ نبيٍّ دعوةٌ مستجابةٌ، فتعجَّل كلُّ نبيٍّ دعوتَه، وإنِّي اختبأتُ دعوتي شفاعة لأمَّتي يوم القيامة، فهي نائلةٌ إن شاء الله مَن مات من أمَّتي لا يشركُ بالله شيئًا)، وهذه الشفاعة تحصلُ من الملائكة والنَّبيِّين والمؤمنين؛ لقوله صلى الله عليه وسلم : (فيقول الله عز وجل : شفعت الملائكة، وشفع النَّبيُّون، وشفع المؤمنون، ولَم يبق إلَّا أرحمُ الرَّاحمين...) الحديث.", "page": 178, "id": "unit-17__lesson-03__b06", "inline": [{"t": "emphasis", "s": "ومنها:", "role": "emphasis"}, {"t": "text", "s": " الشفاعة في إخراج أهل الكبائر من النار، وقد تواترت بذلك الأحاديث؛ قال رسول الله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(لكلِّ نبيٍّ دعوةٌ مستجابةٌ، فتعجَّل كلُّ نبيٍّ دعوتَه، وإنِّي اختبأتُ دعوتي شفاعة لأمَّتي يوم القيامة، فهي نائلةٌ إن شاء الله مَن مات من أمَّتي لا يشركُ بالله شيئًا)", "role": "emphasis"}, {"t": "text", "s": "، وهذه الشفاعة تحصلُ من الملائكة والنَّبيِّين والمؤمنين؛ لقوله "}, {"t": "honorific", "s": "صلى الله عليه وسلم"}, {"t": "text", "s": " : "}, {"t": "emphasis", "s": "(فيقول الله", "role": "emphasis"}, {"t": "text", "s": " "}, {"t": "honorific", "s": "عز وجل"}, {"t": "text", "s": " "}, {"t": "emphasis", "s": ": شفعت الملائكة، وشفع النَّبيُّون، وشفع المؤمنون، ولَم يبق إلَّا أرحمُ الرَّاحمين...)", "role": "emphasis"}, {"t": "text", "s": " الحديث."}]}, {"type": "paragraph", "md": "9- ومن الإيمان باليوم الآخر: الإيمانُ بالجنَّة والنار، وأنَّهما موجودتان الآن، وأنَّهما باقيتان إلى غير نهاية، فقد أعدَّ اللهُ الجنَّةَ لأوليائه، وأعدَّ النَّارَ لأعدائه، فمن الآيات التي فيها إعداد الجنَّة لأوليائه قوله تعالى: ﴿۞وَسَارِعُوٓاْ إِلَىٰ مَغۡفِرَةٖ مِّن رَّبِّكُمۡ وَجَنَّةٍ عَرۡضُهَا ٱلسَّمَٰوَٰتُ وَٱلۡأَرۡضُ أُعِدَّتۡ لِلۡمُتَّقِينَ ۝١٣٣﴾، ومن الآيات التي فيها إعداد النار لأعدائه قوله تعالى: ﴿وَٱتَّقُواْ ٱلنَّارَ ٱلَّتِيٓ أُعِدَّتۡ لِلۡكَٰفِرِينَ ۝١٣١﴾، وقوله: ﴿فَٱتَّقُواْ ٱلنَّارَ ٱلَّتِي وَقُودُهَا ٱلنَّاسُ وَٱلۡحِجَارَةُۖ أُعِدَّتۡ لِلۡكَٰفِرِينَ ۝٢٤﴾ ويدلُّ من السُّنَّة لكونهما موجودتَين الآن حديث الكسوف، وفيه: قالوا: يا رسول الله! رأيناك تناولتَ شيئًا في مقامك، ثم رأيناك كَعْكَعْتَ، قال صلى الله عليه وسلم : (إنِّي رأيتُ الجنَّةَ، فتناولتُ عنقودًا، ولو أصبته لأكلتُم منه ما بقيت الدنيا، وأُريتُ النار، فلَم أرَ منظَرًا كاليوم قطُّ أفظع، ورأيتُ أكثرَ أهلها النساء..).", "page": 179, "id": "unit-17__lesson-03__b07", "inline": [{"t": "emphasis", "s": "9- ومن الإيمان باليوم الآخر: الإيمانُ بالجنَّة والنار", "role": "emphasis"}, {"t": "text", "s": "، وأنَّهما موجودتان الآن، وأنَّهما باقيتان إلى